import { isYYYYMMDD, parseToYYYYMMDD, tryCreateYYYYMMDD } from '@moneyworks/utilities';

// Parse user input safely
function processDateInput(input: string): YYYYMMDD | null {
  // Try direct YYYYMMDD format first
  if (isYYYYMMDD(input)) {
    return input;
  }

  // Try parsing other formats
  try {
    return parseToYYYYMMDD(input);
  } catch {
    return null;
  }
}

// Validate date ranges
function validateDateRange(start: string, end: string): boolean {
  const startDate = tryCreateYYYYMMDD(start);
  const endDate = tryCreateYYYYMMDD(end);

  if (!startDate || !endDate) {
    return false;
  }

  return startDate <= endDate;
}

