import { p, Period, addPeriods, periodToDateRange, PeriodUtils } from '@moneyworks/utilities';

// Financial year handling
class FinancialYear {
  constructor(
    private startPeriod: Period,
    private endPeriod: Period
  ) {}

  static fromYear(year: number): FinancialYear {
    return new FinancialYear(
      p`${year}07`,     // July start
      p`${year + 1}06`  // June end
    );
  }

  contains(period: Period): boolean {
    return period >= this.startPeriod && period <= this.endPeriod;
  }

  getPeriods(): Period[] {
    const periods: Period[] = [];
    let current = this.startPeriod;

    while (current <= this.endPeriod) {
      periods.push(current);
      current = addPeriods(current, 1);
    }

    return periods;
  }
}

const fy24 = FinancialYear.fromYear(2023);
const periods = fy24.getPeriods();

// Get date ranges for each period
const quarters = [
  { q: 'Q1', periods: periods.slice(0, 3) },
  { q: 'Q2', periods: periods.slice(3, 6) },
  { q: 'Q3', periods: periods.slice(6, 9) },
  { q: 'Q4', periods: periods.slice(9, 12) }
].map(q => ({
  quarter: q.q,
  start: periodToDateRange(q.periods[0]).start,
  end: periodToDateRange(q.periods[2]).end
}));

