import { Brand, Unbrand } from '@moneyworks/utilities';

// Define custom branded types
type InvoiceNumber = Brand<string, 'InvoiceNumber'>;
type CustomerID = Brand<string, 'CustomerID'>;
type Amount = Brand<number, 'Amount'>;
type Percentage = Brand<number, 'Percentage'>;

// Create validators
function isInvoiceNumber(value: string): value is InvoiceNumber {
  return /^INV-\d{6}$/.test(value);
}

function isPercentage(value: number): value is Percentage {
  return value >= 0 && value <= 100;
}

// Create factory functions
function createInvoiceNumber(value: string): InvoiceNumber {
  if (!isInvoiceNumber(value)) {
    throw new Error(`Invalid invoice number format: ${value}`);
  }
  return value;
}

function createPercentage(value: number): Percentage {
  if (!isPercentage(value)) {
    throw new Error(`Percentage must be between 0 and 100: ${value}`);
  }
  return value;
}

// Tagged template for invoice numbers
function inv(strings: TemplateStringsArray, ...values: any[]): InvoiceNumber {
  const num = values[0];
  return createInvoiceNumber(`INV-${String(num).padStart(6, '0')}`);
}

// Use in your domain
interface TaxCalculation {
  rate: Percentage;
  amount: Amount;
  calculate(base: Amount): Amount;
}

const gst: TaxCalculation = {
  rate: createPercentage(10),
  amount: 0 as Amount,
  calculate(base: Amount): Amount {
    const rate = Unbrand(this.rate);
    const baseAmount = Unbrand(base);
    return (baseAmount * rate / 100) as Amount;
  }
};

